import { test, expect } from '@playwright/test';

test('User login with invalid password', async ({ page }) => {
  await page.goto('https://example.com/login');
  await page.locator('input[name="username"]').fill('validusername');
  await page.locator('input[name="password"]').fill('invalidpassword');
  await page.locator('button[type="submit"]').click();
  await expect(page.locator('text=Invalid password')).toBeVisible();
  await expect(page.locator('text=Login successful')).not.toBeVisible();
});

import { test, expect } from '@playwright/test';

test('Successful Logout', async ({ page }) => {
  await page.goto('https://the-internet.herokuapp.com/login');
  await page.locator('input[name="username"]').fill('tomsmith');
  await page.locator('input[name="password"]').fill('SuperSecretPassword!');
  await page.locator('button[type="submit"]').click();
  await page.locator('a[href="#"]').click();
  await expect(page.locator('h2')).toContainText('Login Page');
  await expect(page.locator('div.flash.success')).toContainText('You logged out of the secure area!');
});

test('Logout from Multiple Sessions', async ({ page }) => {
  await page.goto('https://the-internet.herokuapp.com/login');
  await page.locator('input[name="username"]').fill('tomsmith');
  await page.locator('input[name="password"]').fill('SuperSecretPassword!');
  await page.locator('button[type="submit"]').click();
  const context = await page.context();
  const newPage = await context.newPage();
  await newPage.goto('https://the-internet.herokuapp.com/login');
  await newPage.locator('input[name="username"]').fill('tomsmith');
  await newPage.locator('input[name="password"]').fill('SuperSecretPassword!');
  await newPage.locator('button[type="submit"]').click();
  await page.locator('a[href="#"]').click();
  await expect(page.locator('h2')).toContainText('Login Page');
  await expect(newPage.locator('h2')).toContainText('Login Page');
  await expect(page.locator('div.flash.success')).toContainText('You logged out of the secure area!');
});

test('Logout with Pending Changes', async ({ page }) => {
  await page.goto('https://the-internet.herokuapp.com/login');
  await page.locator('input[name="username"]').fill('tomsmith');
  await page.locator('input[name="password"]').fill('SuperSecretPassword!');
  await page.locator('button[type="submit"]').click();
  await page.locator('input[name="username"]').fill('newusername');
  await page.locator('a[href="#"]').click();
  await expect(page.locator('div.flash.success')).toContainText('You logged out of the secure area!');
});

test('Logout with Invalid Session', async ({ page }) => {
  await page.goto('https://the-internet.herokuapp.com/login');
  await page.locator('input[name="username"]').fill('invaliduser');
  await page.locator('input[name="password"]').fill('invalidpassword');
  await page.locator('button[type="submit"]').click();
  await page.locator('a[href="#"]').click();
  await expect(page.locator('h2')).toContainText('Login Page');
  await expect(page.locator('div.flash.error')).toContainText('Your username is invalid!');
});

test('Logout with Network Error', async ({ page }) => {
  await page.goto('https://the-internet.herokuapp.com/login');
  await page.locator('input[name="username"]').fill('tomsmith');
  await page.locator('input[name="password"]').fill('SuperSecretPassword!');
  await page.locator('button[type="submit"]').click();
  await page.setOfflineMode(true);
  await page.locator('a[href="#"]').click();
  await expect(page.locator('div.flash.error')).toContainText('Failed to log out due to network error');
  await page.setOfflineMode(false);
  await page.locator('a[href="#"]').click();
  await expect(page.locator('h2')).toContainText('Login Page');
  await expect(page.locator('div.flash.success')).toContainText('You logged out of the secure area!');
});

